mapper.sql:


where 1 = 1  and not exists (select 1 from td_courseware td where td.file_id = tls.id)
and not exists (select 1 from td_job_authentication tja where tja.file_id = tls.id)
and not exists (select 1 from td_teacher_apply tta where tta.file_id = tls.id)




  and (tls.name like #{criteria.blurry,jdbcType=VARCHAR}
    or tls.suffix like #{criteria.blurry,jdbcType=VARCHAR}
    or tls.type like #{criteria.blurry,jdbcType=VARCHAR}
    or tls.operate like #{criteria.blurry,jdbcType=VARCHAR}
    or tls.file_size like #{criteria.blurry,jdbcType=VARCHAR})




  and tls.create_time >= #{criteria.startTime,jdbcType=TIMESTAMP}




  and tls.create_time <= #{criteria.endTime,jdbcType=TIMESTAMP}

mapper.update:

update tool_local_storage
   set name        = #{name,jdbcType=VARCHAR},
       update_time = #{updateTime,jdbcType=TIMESTAMP},
       update_by   = #{updateBy,jdbcType=BIGINT}
 where id = #{id,jdbcType=BIGINT}
